import{_ as o,o as d,c as a,a2 as c}from"./chunks/framework.BQ1gajhD.js";const h=JSON.parse('{"title":"小程序全量内容同步设计","description":"","frontmatter":{},"headers":[],"relativePath":"superpowers/specs/2026-07-23-miniapp-full-content-sync-design.md","filePath":"superpowers/specs/2026-07-23-miniapp-full-content-sync-design.md","lastUpdated":1784798095000}'),i={name:"superpowers/specs/2026-07-23-miniapp-full-content-sync-design.md"};function r(t,e,n,s,l,p){return d(),a("div",null,[...e[0]||(e[0]=[c('<h1 id="小程序全量内容同步设计" tabindex="-1">小程序全量内容同步设计 <a class="header-anchor" href="#小程序全量内容同步设计" aria-label="Permalink to &quot;小程序全量内容同步设计&quot;">​</a></h1><h2 id="目标" tabindex="-1">目标 <a class="header-anchor" href="#目标" aria-label="Permalink to &quot;目标&quot;">​</a></h2><p>将 <code>docs/</code> 中现有的北京旅行 Markdown 内容完整转换为 <code>beijing-travel-mp</code> 可离线使用的静态数据。小程序列表可检索所有景点，父级景点和目录内子景点均可独立打开详情；Web 端攻略文章也提供完整小程序详情。</p><h2 id="内容范围" tabindex="-1">内容范围 <a class="header-anchor" href="#内容范围" aria-label="Permalink to &quot;内容范围&quot;">​</a></h2><ul><li>景点来源：<code>docs/landmarks</code>、<code>docs/museums</code>、<code>docs/parks</code>、<code>docs/religion</code>、<code>docs/history</code> 下除各目录入口页外的每篇 Markdown。</li><li>攻略来源：<code>docs/guide</code> 下除入口页外的每篇 Markdown。</li><li>嵌套目录内的 <code>index.md</code> 作为父级景点，其他 Markdown 作为子景点；二者均生成独立稳定 ID。</li><li>顶级分类页不生成无内容的列表项。</li></ul><h2 id="数据与同步架构" tabindex="-1">数据与同步架构 <a class="header-anchor" href="#数据与同步架构" aria-label="Permalink to &quot;数据与同步架构&quot;">​</a></h2><p>以 Markdown 为唯一内容源。同步脚本递归解析文件、提取标题、首图、首段摘要、信息表格和二三级标题正文，输出 <code>data/places.json</code> 与 <code>data/guides.json</code>；随后从 JSON 生成同内容的 CommonJS 数据模块。小程序仅通过 <code>utils/data.js</code> 读取 JS 模块，以规避部分微信开发者工具不能运行时 <code>require(JSON)</code> 的兼容性问题。</p><p>景点条目至少包含：<code>id</code>、<code>name</code>、<code>categoryId</code>、<code>summary</code>、<code>tags</code>、<code>cover</code>、<code>featured</code>、<code>funRank</code>、<code>info</code>、<code>sections</code>。保留可选 <code>parentId</code>、<code>sourcePath</code> 与 <code>relatedPlaceIds</code>，用于展示父子关联及定位来源。攻略条目包含 <code>id</code>、<code>title</code>、<code>summary</code>、<code>icon</code> 与完整 <code>sections</code>。</p><h2 id="显示与降级" tabindex="-1">显示与降级 <a class="header-anchor" href="#显示与降级" aria-label="Permalink to &quot;显示与降级&quot;">​</a></h2><p>现有列表与详情页沿用现有组件和布局，不新增网络依赖。正文段落使用换行保留 Markdown 的阅读层级；表格转换为标签和值的基础信息。图片缺失、外链不可用或无法识别时使用项目现有 SVG 默认封面，避免空白卡片。</p><h2 id="可重复性与质量门槛" tabindex="-1">可重复性与质量门槛 <a class="header-anchor" href="#可重复性与质量门槛" aria-label="Permalink to &quot;可重复性与质量门槛&quot;">​</a></h2><ul><li>同步脚本可重复运行，不会累积重复条目。</li><li>生成数量必须与 Web 可迁移 Markdown 数量一致，且每个条目有非空标题、摘要和至少一个内容区块。</li><li>JSON 与对应 <code>.js</code> CommonJS 模块数据逐字等价。</li><li>现有行程引用的景点 ID 必须全部继续存在。</li><li>测试覆盖递归子景点、父级目录页、攻略页、数据模块一致性和行程引用完整性。</li></ul><h2 id="范围边界" tabindex="-1">范围边界 <a class="header-anchor" href="#范围边界" aria-label="Permalink to &quot;范围边界&quot;">​</a></h2><p>本次只迁移仓库中已有的 Web 内容；不联网补写、校验或更新官方票务、开放时间等时效信息。</p>',14)])])}const m=o(i,[["render",r]]);export{h as __pageData,m as default};
